// Solution
import React from 'react';

const { useState, memo } = React;

function MemoizedComponent({ obj }) {
  const memoizationFunction = memo(() => JSON.stringify(obj));
  return (
    <div>
      {memoizationFunction()} // Returns the string representation of the current object
    </div>
  );
}
